BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?itemFlow ?tgt ?tgtName ?src ?srcName WHERE {
  VALUES ?srcDoc {
    <http://api.koneksys.com/cameo/TMT/block/TMT::Project::Work%2520Packages::Telescope::WorkPackages::Control::Alignment%2520and%2520Phasing%2520System::Systems%2520Engineering::03%2520Processes::Information%2520Flow::Requirements%2520Information%2520Flow::L2%2520APS%2520Requirements%2520Document>
  }
  # Find item-flow where the L2 doc is either the direct target or related element
  {
    ?itemFlow rdf:type vocab:item%20flow .
    ?itemFlow vocab:InformationFlow_informationTarget ?srcDoc .
  }
  UNION
  {
    ?itemFlow rdf:type vocab:item%20flow .
    ?itemFlow vocab:Relationship_relatedElement ?srcDoc .
  }

  # Now pick the same itemFlow's target and check if it is inside the flowdown doc hierarchy
  VALUES ?flowdownDoc {
    <http://api.koneksys.com/cameo/TMT/document/TMT::Project::Work%2520Packages::Telescope::WorkPackages::Control::Alignment%2520and%2520Phasing%2520System::Systems%2520Engineering::09%2520Views::TMT-APS-SE::TMT-APS%2520Requirements%2520Flow-down::TMT-APS%2520Requirements%2520Flow-down>
  }

  ?itemFlow vocab:DirectedRelationship_target ?tgt .
  ?flowdownDoc vocab:Element_ownedElement+ ?tgt .

  OPTIONAL { ?itemFlow vocab:InformationFlow_informationSource ?src . }
  OPTIONAL { ?tgt vocab:NamedElement_name ?tgtName . }
  OPTIONAL { ?src vocab:NamedElement_name ?srcName . }
}
LIMIT 25
